{
  "grammar": [
    {
      "pattern": "Subject + 從 + Time/Place + 到 + Time/Place + (的) + Duration/Activity",
      "structure": ["Subject", "從", "Time/Place", "到", "Time/Place", "Duration/Activity"],
      "explanation_en": "Use this structure to express a range from one point to another, covering time, place, or activity duration.",
      "title": "從...到... (From...To...)",
      "meaning": "Indicates a range from a starting point to an ending point.",
      "when_to_use": ["When describing a time period", "When describing a spatial range", "When listing activities in sequence"],
      "when_not_to_use": ["When the range is not clearly defined", "When using single points without a range"],
      "pragmatic_notes": "In Taiwan, this structure is very common in daily conversation for schedules, directions, and summaries.",
      "word_order_notes": "The structure must follow '從 + starting point + 到 + ending point'. The duration or activity comes after.",
      "english_contrast": "English uses 'from...to...' similarly, but Chinese often omits the verb when the context is clear.",
      "korean_contrast": "Korean uses '~에서 ~까지' which is similar but placed after nouns, while Chinese uses prepositions before nouns.",
      "negative_examples": [
        {
          "text": "我從早上到晚上工作。",
          "error": "Missing duration or activity after the range; should specify what happens from morning to evening."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我從早上到晚上工作。",
          "error": "The sentence is grammatically correct but ambiguous; better to add '都在工作' for clarity."
        }
      ],
      "transformation_drills": ["Change '從台北到高雄' into a sentence about travel time.", "Convert '從星期一到星期五' into a sentence about work schedule."],
      "production_drills": ["Describe your daily routine using 從...到...", "Explain the distance from your home to school using 從...到..."],
      "common_error_patterns": ["Forgetting to include the activity after the range", "Using 從 and 到 with incorrect word order"],
      "repair_feedback": {
        "word_order": "Remember: 從 comes before the starting point, 到 before the ending point.",
        "politeness": "This structure is neutral; no special politeness needed.",
        "vocabulary": "Use time words like 早上, 晚上, 今天, 明天 or place words like 台北, 高雄."
      }
    },
    {
      "pattern": "Subject + 除了 + Noun/Phrase + 以外 + 還/也 + Verb/Adjective",
      "structure": ["Subject", "除了", "Noun/Phrase", "以外", "還/也", "Verb/Adjective"],
      "explanation_en": "Use this structure to say 'besides' or 'in addition to' something, indicating an extra item or action.",
      "title": "除了...以外 (Besides/In Addition To...)",
      "meaning": "Indicates inclusion of an additional item or action beyond the mentioned one.",
      "when_to_use": ["When listing multiple items or activities", "When emphasizing an extra element", "When comparing options"],
      "when_not_to_use": ["When the list is exhaustive without extra items", "When using negative sentences without 以外"],
      "pragmatic_notes": "In Taiwan, this is often used in recommendations or when sharing preferences, e.g., '除了珍珠奶茶以外，我也喜歡喝咖啡。'",
      "word_order_notes": "The structure is fixed: 除了 + noun/phrase + 以外 + 還/也 + verb/adjective. 以外 can sometimes be omitted in casual speech.",
      "english_contrast": "English uses 'besides' or 'in addition to' at the beginning of the sentence, while Chinese places 除了 before the noun.",
      "korean_contrast": "Korean uses '~외에도' which is similar but placed after the noun, while Chinese uses 除了 before the noun.",
      "negative_examples": [
        {
          "text": "我除了咖啡以外不喝。",
          "error": "Missing 還/也; the sentence is incomplete without indicating what else is done."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我除了咖啡以外不喝。",
          "error": "Should be '我除了咖啡以外，還喝紅茶。' to show addition."
        }
      ],
      "transformation_drills": ["Change '除了中文以外，我也學英文。' into a sentence about hobbies.", "Convert '除了看電影以外，他還喜歡聽音樂。' into a sentence about food."],
      "production_drills": ["Tell a friend what you like besides your main hobby using 除了...以外.", "Describe your travel plans including extra destinations using 除了...以外."],
      "common_error_patterns": ["Omitting 還/也 after 以外", "Using 除了 without 以外 in formal contexts"],
      "repair_feedback": {
        "word_order": "Place 除了 before the noun and 以外 after it, then add 還/也 before the verb.",
        "politeness": "This structure is neutral; can be used in both formal and informal settings.",
        "vocabulary": "Use nouns like 咖啡, 紅茶, 電影, 音樂 or activities like 看書, 運動."
      }
    },
    {
      "pattern": "Subject + 不但 + Adjective/Verb + 而且 + Adjective/Verb",
      "structure": ["Subject", "不但", "Adjective/Verb", "而且", "Adjective/Verb"],
      "explanation_en": "Use this structure to say 'not only...but also...' to emphasize two qualities or actions.",
      "title": "不但...而且... (Not Only...But Also...)",
      "meaning": "Indicates that two things are both true, with emphasis on the second.",
      "when_to_use": ["When describing multiple positive traits", "When listing achievements or skills", "When giving compliments"],
      "when_not_to_use": ["When the two items are contradictory", "When using negative sentences without adjustment"],
      "pragmatic_notes": "In Taiwan, this is often used in formal or semi-formal contexts like interviews or self-introductions.",
      "word_order_notes": "不但 comes before the first adjective/verb, and 而且 before the second. The subject is placed before 不但.",
      "english_contrast": "English uses 'not only...but also...' with similar word order, but Chinese does not invert the subject.",
      "korean_contrast": "Korean uses '~뿐만 아니라 ~도' which is similar but placed after the verb, while Chinese uses pre-verbal adverbs.",
      "negative_examples": [
        {
          "text": "我不但會說中文而且會說英文。",
          "error": "Correct structure but missing 也 before 會說英文 for natural flow; '不但...而且...' is fine but '也' is optional."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我不但會說中文而且會說英文。",
          "error": "This sentence is actually correct; no error here."
        }
      ],
      "transformation_drills": ["Change '他不但聰明而且認真。' into a sentence about food.", "Convert '這家餐廳不但便宜而且好吃。' into a sentence about a person."],
      "production_drills": ["Describe your best friend using 不但...而且...", "Talk about a restaurant you like using 不但...而且..."],
      "common_error_patterns": ["Using 不但 with only one adjective", "Forgetting 而且 before the second item"],
      "repair_feedback": {
        "word_order": "Place 不但 before the first adjective/verb and 而且 before the second.",
        "politeness": "This structure is polite and suitable for compliments.",
        "vocabulary": "Use adjectives like 聰明, 認真, 便宜, 好吃 or verbs like 會說, 會做."
      }
    }
  ]
}
